// ============================================================
// WF-ANALYZER Chang 2: ENGINE PHAN TICH NGUONG (chay trong n8n)
// ============================================================
// Nhan toan bo dong log da parse (tu node truoc), dem theo IP trong
// cua so thoi gian truot, phan loai PORT_SCAN / BRUTE_FORCE / DDOS.
// Day la "bo nao" cua he thong - lam trong n8n de the hien nang luc
// dieu phoi + phan tich cua n8n (khong day het sang Python rieng).

const input = $input.first().json;
const lines = input.sample_last_10 ? null : null; // placeholder, xem duoi

// ---- Lay lai toan bo dong da parse tu node Parse Log Lines ----
// (Node truoc chi tra ve sample_last_10 de xem nhanh; o day ta parse
//  LAI toan bo raw text de co ĐẦY ĐỦ du lieu cho engine dem nguong.)
const content = $('Extract Text').first().json.data || '';
const rawLines = content.split('\n').filter(l => l.trim());

// ---- Cau hinh (giu dung can cu nhu ban Python truoc) ----
const INTERNAL_NETS = ['192.168.10.', '192.168.11.', '192.168.12.', '192.168.20.'];
const IGNORE_PREFIXES = ['169.254.', '224.', '239.', '255.', '0.', '127.'];
const IGNORE_EXACT = ['192.168.183.1', '192.168.10.1'];

const THRESHOLDS = {
  BRUTE_FORCE: { count: 5, window: 60 },          // 5 lan fail dang nhap / 60s
  PORT_SCAN:   { distinctPorts: 15, window: 10 },  // 15 port khac nhau / 10s
  CONN_FLOOD:  { count: 100, window: 10 },         // 100 su kien / 10s (1 IP)
  DDOS_SPREAD: { distinctIps: 20, window: 10 },    // 20 IP khac nhau / 10s
};

function isInternal(ip) { return ip && INTERNAL_NETS.some(n => ip.startsWith(n)); }
function shouldIgnore(ip) {
  if (!ip) return true;
  if (IGNORE_EXACT.includes(ip)) return true;
  return IGNORE_PREFIXES.some(p => ip.startsWith(p));
}
function pickAttacker(src, dst) {
  if (src && !isInternal(src)) return src;
  if (dst && !isInternal(dst)) return dst;
  return src || dst;
}

// ---- Regex bóc tách ----
const RE_ANY_IP = /\b(\d{1,3}(?:\.\d{1,3}){3})\b/g;
const RE_FILTERLOG_TCP = /,tcp,\d+,(\d{1,3}(?:\.\d{1,3}){3}),(\d{1,3}(?:\.\d{1,3}){3}),(\d+),(\d+),[^,]*,([A-Z]*)/;
const RE_SSH_FAIL = /Failed password for (?:invalid user )?(\S+) from (\d{1,3}(?:\.\d{1,3}){3}) port (\d+)/;

// ---- Parse 1 dong -> tin hieu tho (giong ham extract_signal ben Python) ----
function extractSignal(raw) {
  const low = raw.toLowerCase();

  // Auth log SSH fail -> tin hieu brute force
  const authM = raw.match(RE_SSH_FAIL);
  if (authM) {
    const ip = authM[2];
    if (shouldIgnore(ip) || isInternal(ip)) return null;
    return { kind: 'auth_fail', src_ip: ip, dst_port: 22 };
  }

  // Filterlog: firewall block/pass
  if (low.includes('filterlog') && (low.includes(',block,') || low.includes(',pass,'))) {
    const ips = [...raw.matchAll(RE_ANY_IP)].map(m => m[1]);
    if (ips.length < 2) return null;
    const [src, dst] = ips;
    const attacker = pickAttacker(src, dst);
    if (isInternal(attacker) || shouldIgnore(attacker)) return null;

    const tcpM = raw.match(RE_FILTERLOG_TCP);
    let dport = null, flags = null;
    if (tcpM) { dport = parseInt(tcpM[4], 10); flags = tcpM[5]; }

    const kind = (flags === 'S') ? 'syn' : 'fw_block';
    return { kind, src_ip: attacker, dst_port: dport };
  }
  return null;
}

// ---- Engine dem theo IP trong cua so thoi gian (dung timestamp THU NHAN) ----
const events = {};      // ip -> [{ts, port, kind}]
const globalEvents = []; // toan he thong (cho DDoS phan tan)

function nowFromLine(line) {
  const tab = line.indexOf('\t');
  if (tab < 0) return Date.now() / 1000;
  const tsStr = line.slice(0, tab);
  const t = Date.parse(tsStr);
  return isNaN(t) ? Date.now() / 1000 : t / 1000;
}

const detections = [];   // ket qua: IP nao vuot nguong, loai gi

for (const line of rawLines) {
  const tab = line.indexOf('\t');
  const raw = tab >= 0 ? line.slice(tab + 1) : line;
  const now = nowFromLine(line);

  const sig = extractSignal(raw);
  if (!sig) continue;

  const ip = sig.src_ip;
  if (!events[ip]) events[ip] = [];
  events[ip].push({ ts: now, port: sig.dst_port, kind: sig.kind });
  globalEvents.push({ ts: now, ip });
}

// ---- Xet nguong cho tung IP (dua tren toan bo su kien da gom) ----
function countInWindow(evList, now, windowSec, kindFilter, portFilter) {
  return evList.filter(e =>
    (now - e.ts) <= windowSec &&
    (!kindFilter || e.kind === kindFilter) &&
    (portFilter === undefined || e.port === portFilter)
  ).length;
}
function distinctPortsInWindow(evList, now, windowSec, kindFilter) {
  const ports = new Set();
  evList.forEach(e => {
    if ((now - e.ts) <= windowSec && (!kindFilter || e.kind === kindFilter) && e.port != null) {
      ports.add(e.port);
    }
  });
  return ports.size;
}

const nowMax = rawLines.length ? nowFromLine(rawLines[rawLines.length - 1]) : Date.now() / 1000;

for (const ip of Object.keys(events)) {
  const evList = events[ip];
  let found = null;

  // 1) BRUTE_FORCE: nhieu auth_fail cung 1 port trong window
  const authFails = evList.filter(e => e.kind === 'auth_fail');
  if (authFails.length) {
    const byPort = {};
    authFails.forEach(e => { byPort[e.port] = (byPort[e.port] || 0) + 1; });
    for (const port of Object.keys(byPort)) {
      const cnt = countInWindow(evList, nowMax, THRESHOLDS.BRUTE_FORCE.window, 'auth_fail', Number(port));
      if (cnt >= THRESHOLDS.BRUTE_FORCE.count) { found = { type: 'BRUTE_FORCE', metric: cnt }; break; }
    }
  }

  // 2) CONN_FLOOD: tong su kien 1 IP qua nhieu trong window
  if (!found) {
    const total = countInWindow(evList, nowMax, THRESHOLDS.CONN_FLOOD.window);
    if (total >= THRESHOLDS.CONN_FLOOD.count) found = { type: 'CONN_FLOOD', metric: total };
  }

  // 3) PORT_SCAN: nhieu port khac nhau trong window
  if (!found) {
    const dp = distinctPortsInWindow(evList, nowMax, THRESHOLDS.PORT_SCAN.window, 'fw_block');
    if (dp >= THRESHOLDS.PORT_SCAN.distinctPorts) found = { type: 'PORT_SCAN', metric: dp };
  }

  if (found) detections.push({ src_ip: ip, event_type: found.type, metric: found.metric });
}

// 4) DDoS phan tan: nhieu IP khac nhau cung tan cong trong window
const recentGlobal = globalEvents.filter(e => (nowMax - e.ts) <= 10);
const distinctIps = new Set(recentGlobal.map(e => e.ip)).size;
if (distinctIps >= THRESHOLDS.DDOS_SPREAD.distinctIps) {
  detections.push({ src_ip: 'MULTIPLE', event_type: 'DDOS', metric: `${distinctIps} IP` });
}

return [{ json: {
  total_lines_scanned: rawLines.length,
  ips_tracked: Object.keys(events).length,
  detections: detections,
}}];
